/**
 * Set Homepage API
 * Author: generated by Amazon Q
 */

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { verifyToken } from '@/lib/auth';

// POST /api/admin/pages/[id]/set-homepage - Set page as homepage
export async function POST(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  try {
    const authHeader = request.headers.get('authorization');
    const token = authHeader?.replace('Bearer ', '');
    
    if (!token || !verifyToken(token)) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const pageId = params.id;

    // Get the new page
    const newPage = await prisma.page.findUnique({
      where: { id: pageId },
    });

    if (!newPage) {
      return NextResponse.json({ error: 'Page not found' }, { status: 404 });
    }

    // Use transaction to ensure atomic operation
    const result = await prisma.$transaction(async (tx) => {
      const newSlug = `/${newPage.language}`;
      const tempSlug = `temp-${Date.now()}`;
      
      // Step 1: Find any page with the target slug
      const existingPageWithSlug = await tx.page.findUnique({
        where: { slug: newSlug },
      });

      // Step 2: Temporarily change slug if conflict exists
      if (existingPageWithSlug && existingPageWithSlug.id !== pageId) {
        await tx.page.update({
          where: { id: existingPageWithSlug.id },
          data: { slug: tempSlug },
        });
      }

      // Step 3: Unset all homepages
      await tx.page.updateMany({
        where: { isHomepage: true },
        data: { isHomepage: false },
      });

      // Step 4: Set the new homepage
      const updatedPage = await tx.page.update({
        where: { id: pageId },
        data: { 
          isHomepage: true,
          slug: newSlug,
        },
      });

      // Step 5: Restore old page slug
      if (existingPageWithSlug && existingPageWithSlug.id !== pageId) {
        const restoredSlug = `/${existingPageWithSlug.title.toLowerCase().replace(/\s+/g, '-')}`;
        await tx.page.update({
          where: { id: existingPageWithSlug.id },
          data: { slug: restoredSlug },
        });
      }

      return updatedPage;
    });

    return NextResponse.json({ success: true, page: result });
  } catch (error: any) {
    console.error('Set homepage error:', error);
    return NextResponse.json({ 
      error: 'Failed to update homepage', 
      details: error.message 
    }, { status: 500 });
  }
}
